"""Batch validation of supplier STL files using stl_batch_validator_v1 logic."""
import json
import math
import struct
import os


def _cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )

def _sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def _magnitude(v):
    return math.sqrt(v[0]**2 + v[1]**2 + v[2]**2)

def _dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def _normalize(v):
    m = _magnitude(v)
    if m == 0:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)


def _is_binary_stl(path):
    """Returns True if the file looks like a binary STL."""
    with open(path, 'rb') as f:
        header = f.read(80)
        if len(header) < 80:
            return False
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            return False
        tri_count = struct.unpack('<I', count_bytes)[0]
        expected_size = 80 + 4 + tri_count * 50
        actual_size = os.path.getsize(path)
        if actual_size == expected_size:
            return True
    # Check if it starts with 'solid' (ASCII indicator)
    with open(path, 'r', errors='replace') as f:
        first = f.read(256)
    return not first.strip().lower().startswith('solid')


def parse_binary_stl(path):
    issues = []
    triangles = []
    file_size = os.path.getsize(path)
    with open(path, 'rb') as f:
        header = f.read(80)
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            return {'valid': False, 'issues': ['Truncated binary STL header']}
        tri_count = struct.unpack('<I', count_bytes)[0]
        expected_size = 80 + 4 + tri_count * 50
        if file_size != expected_size:
            issues.append(f'Binary file size mismatch: expected {expected_size}, got {file_size}')
        for _ in range(tri_count):
            data = f.read(50)
            if len(data) < 50:
                issues.append('Truncated triangle data')
                break
            vals = struct.unpack('<12fH', data)
            declared_normal = (vals[0], vals[1], vals[2])
            v1 = (vals[3], vals[4], vals[5])
            v2 = (vals[6], vals[7], vals[8])
            v3 = (vals[9], vals[10], vals[11])
            triangles.append((declared_normal, [v1, v2, v3]))
    return issues, triangles


def parse_ascii_stl(path):
    issues = []
    triangles = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f'Malformed facet normal at line {i+1}')
                i += 1
                continue
            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vparts = vline.split()
                            try:
                                vertices.append((float(vparts[1]), float(vparts[2]), float(vparts[3])))
                            except (IndexError, ValueError):
                                issues.append(f'Malformed vertex at line {i+1}')
                        i += 1
            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f'Incomplete triangle near line {i+1}')
            continue
        i += 1
    return issues, triangles


def validate_stl(path):
    issues = []
    try:
        if _is_binary_stl(path):
            parse_issues, triangles = parse_binary_stl(path)
        else:
            parse_issues, triangles = parse_ascii_stl(path)
        issues.extend(parse_issues)
    except Exception as e:
        return {'valid': False, 'issues': [f'Parse error: {e}']}

    if not triangles:
        issues.append('No valid faces found')
        return {'valid': False, 'issues': issues}

    # Manifold check
    edge_count = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j+1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    non_manifold = sum(1 for cnt in edge_count.values() if cnt > 2)
    if open_edges > 0:
        issues.append(f'open_edges:{open_edges}')
    if non_manifold > 0:
        issues.append(f'non_manifold_edges:{non_manifold}')

    # Degenerate triangles
    degen = 0
    for _, verts in triangles:
        v1, v2, v3 = verts
        cross = _cross(_sub(v2, v1), _sub(v3, v1))
        if _magnitude(cross) < 1e-10:
            degen += 1
    if degen > 0:
        issues.append(f'degenerate_triangles:{degen}')

    # Duplicate faces
    face_set = set()
    dup = 0
    for _, verts in triangles:
        key = tuple(sorted(tuple(round(x, 6) for x in v) for v in verts))
        if key in face_set:
            dup += 1
        face_set.add(key)
    if dup > 0:
        issues.append(f'duplicate_faces:{dup}')

    # Inverted normals check
    inverted = 0
    for declared_normal, verts in triangles:
        v1, v2, v3 = verts
        computed = _cross(_sub(v2, v1), _sub(v3, v1))
        mag = _magnitude(computed)
        if mag < 1e-10:
            continue  # degenerate, skip
        cn = _normalize(computed)
        dn = _normalize(declared_normal)
        # If declared normal is zero vector, skip
        if _magnitude(declared_normal) < 1e-10:
            continue
        dot = _dot(cn, dn)
        if dot < 0:
            inverted += 1
    if inverted > 0:
        issues.append(f'inverted_normals:{inverted}')

    return {'valid': len(issues) == 0, 'issues': issues}


def map_reason(issues):
    """Map issue list to a single primary reason string."""
    for issue in issues:
        if 'inverted_normals' in issue:
            return 'inverted_normals'
        if 'open_edges' in issue:
            return 'open_edges'
        if 'non_manifold' in issue:
            return 'non_manifold_edges'
        if 'degenerate' in issue:
            return 'degenerate_triangles'
        if 'duplicate' in issue:
            return 'duplicate_faces'
        if 'file size' in issue.lower() or 'mismatch' in issue.lower():
            return 'binary_size_mismatch'
        if 'No valid faces' in issue:
            return 'no_faces'
    return issues[0] if issues else 'unknown'


results = []
for i in range(1, 51):
    fname = f'supplier_{i:03d}.stl'
    result = validate_stl(fname)
    entry = {'file': fname, 'valid': result['valid']}
    if not result['valid']:
        entry['reason'] = map_reason(result['issues'])
        entry['details'] = result['issues']
    results.append(entry)
    status = 'PASS' if result['valid'] else f'FAIL ({entry.get("reason", "")})'  
    print(f'{fname}: {status}')

with open('validation_report.json', 'w') as f:
    # Write report without details (as per spec)
    report_results = []
    for r in results:
        entry = {'file': r['file'], 'valid': r['valid']}
        if not r['valid']:
            entry['reason'] = r['reason']
        report_results.append(entry)
    json.dump({'results': report_results}, f, indent=2)

print('\nDone. Report written to validation_report.json')

